import{_ as a,W as r,X as t,Y as h,Z as e,a0 as d}from"./framework-91490e6a.js";const n="/assets/images/HOME.jpeg",i={},s=e("p",null,"刚开始租房就和开荒一样，这也缺那也缺，每过一会儿就会发现一个新的缺的东西。",-1),o=e("p",null,"终于搬到了新租的房子里。这是我第一次租房，发现好多事情没有准备好，早知道的话可以做得更好的。",-1),c=e("figure",null,[e("img",{src:n,alt:"新家第一周的样子",tabindex:"0",loading:"lazy"}),e("figcaption",null,"新家第一周的样子")],-1),p=d('<h1 id="第一天" tabindex="-1"><a class="header-anchor" href="#第一天" aria-hidden="true">#</a> 第一天</h1><p>洗澡、睡觉发现没东西。我急忙美团叫了个床单、被子、枕头、浴巾，勉强用了。我将电吹风打包了，所以就导致我还没得吹头发，非常难受。下次搬家第一天一定要带上这些东西，不然搬家忙碌了一周之后，都没法好好休息！</p><h1 id="第二天" tabindex="-1"><a class="header-anchor" href="#第二天" aria-hidden="true">#</a> 第二天</h1><p>直接去宜家升级了昨晚临时用的各种用品。并且买了个瓜，但是我发现——我根本没配套吃瓜设施！于是直接买了一套厨具和餐具。</p><h1 id="第三天" tabindex="-1"><a class="header-anchor" href="#第三天" aria-hidden="true">#</a> 第三天</h1><p>搬家发的快递到了，东西多起来之后，发现需要各种收纳装置，于是买了展柜、抽盒等收纳装置。另外发现上海老房子晒衣服并不是很好晒，所以又买了个干衣机。</p><h1 id="第四天" tabindex="-1"><a class="header-anchor" href="#第四天" aria-hidden="true">#</a> 第四天</h1><p>闲下来了开始打游戏，但是感觉坐得不舒服，本想买个人体工学椅，后来看了一个笑话：</p><blockquote><p>医生：你一定要注意久坐问题，我推荐你站着办公。</p><p>我：最近不是特别流行人体工学椅吗，这种椅子是不是可以解决久坐问题？请问医生你了解吗？</p><p>医生：我了解，非常了解。</p><p>我：那请问您推荐哪把椅子呢？</p><p>医生：哪把不舒服买哪把，这样你坐5分钟就会想站起来了。</p></blockquote><p>于是买了升降桌。</p><h1 id="第五天" tabindex="-1"><a class="header-anchor" href="#第五天" aria-hidden="true">#</a> 第五天</h1><p>展柜到了，但是发现清洁设施不齐全，所以买了纳米五件套以及拖把等清洁设备。</p><h1 id="第六天" tabindex="-1"><a class="header-anchor" href="#第六天" aria-hidden="true">#</a> 第六天</h1><p>升降桌到了，并且第一次做了饭。感觉还是想要个椅子啊，最后基本上定下来买赫曼米勒了。</p><h1 id="结语" tabindex="-1"><a class="header-anchor" href="#结语" aria-hidden="true">#</a> 结语</h1><p>就这样，基本上一周就过去了。刚开始租房，什么都不知道，就会陷入一个过一会儿发现缺一个东西，于是想买，买完之后发现那里又缺一个东西，于是又要买的循环之中。如果早知道需要这些东西，就可以做得更好。就在此记录一下，吃一堑长一智吧。</p>',16);function l(_,u){return r(),t("div",null,[s,o,c,h(" more "),p])}const m=a(i,[["render",l],["__file","Settle_Down.html.vue"]]);export{m as default};
